class minimumStack {
    stack<long long> st, mn;

public:
    void addValue(long long val) {
        st.push(val);
        if (mn.empty() || val <= mn.top()) mn.push(val);
    }

    void removeTopValue() {
        if (st.top() == mn.top()) mn.pop();
        st.pop();
    }

    long long getTopValue() {
        return st.top();
    }

    long long getMinimumValue() {
        return mn.top();
    }
};

