typedef struct {
    long long *st, *mn;
    int top1, top2;
} minimumStack;

minimumStack* createStack() {
    minimumStack* s = malloc(sizeof(minimumStack));
    s->st = s->mn = NULL;
    s->top1 = s->top2 = -1;
    return s;
}

void addValue(minimumStack* s, long long val) {
    s->st = realloc(s->st, sizeof(long long) * (s->top1 + 2));
    s->st[++s->top1] = val;
    if (s->top2 == -1 || val <= s->mn[s->top2]) {
        s->mn = realloc(s->mn, sizeof(long long) * (s->top2 + 2));
        s->mn[++s->top2] = val;
    }
}

void removeTopValue(minimumStack* s) {
    if (s->st[s->top1] == s->mn[s->top2]) s->top2--;
    s->top1--;
}

long long getTopValue(minimumStack* s) {
    return s->st[s->top1];
}

long long getMinimumValue(minimumStack* s) {
    return s->mn[s->top2];
}

