class minimumStack {
    private Stack<Long> st = new Stack<>();
    private Stack<Long> mn = new Stack<>();

    public void addValue(long val) {
        st.push(val);
        if (mn.isEmpty() || val <= mn.peek()) mn.push(val);
    }

    public void removeTopValue() {
        if (st.peek().equals(mn.peek())) mn.pop();
        st.pop();
    }

    public long getTopValue() {
        return st.peek();
    }

    public long getMinimumValue() {
        return mn.peek();
    }
}

