        this.st = [];
        this.mn = [];
    }

    addValue(val) {
        this.st.push(val);
        if (this.mn.length === 0 || val <= this.mn[this.mn.length - 1]) {
            this.mn.push(val);
        }
    }

    removeTopValue() {
        if (this.st[this.st.length - 1] === this.mn[this.mn.length - 1]) {
            this.mn.pop();
        }
        this.st.pop();
    }

    getTopValue() {
        return this.st[this.st.length - 1];
    }

    getMinimumValue() {
        return this.mn[this.mn.length - 1];
    }
}
